package api

import (
	"errors"
	"fmt"
)

var (
	ErrAgentRuntimeNotFound    = errors.New("agent runtime not found")
	ErrCodeInterpreterNotFound = errors.New("code interpreter not found")
	ErrTemplateMissing         = errors.New("resource has no pod template")
	ErrPublicKeyMissing        = errors.New("public key not yet loaded from Router Secret")
)

type SessionNotFoundError struct {
	SessionID string
}

func (e *SessionNotFoundError) Error() string {
	return fmt.Sprintf("session not found: %s", e.SessionID)
}

func NewSessionNotFoundError(sessionID string) error {
	return &SessionNotFoundError{SessionID: sessionID}
}

type SandboxTemplateNotFoundError struct {
	Namespace string
	Name      string
	Kind      string
}

func (e *SandboxTemplateNotFoundError) Error() string {
	return fmt.Sprintf("sandbox template not found: %s/%s of kind %s", e.Namespace, e.Name, e.Kind)
}

func NewSandboxTemplateNotFoundError(namespace, name, kind string) error {
	return &SandboxTemplateNotFoundError{
		Namespace: namespace,
		Name:      name,
		Kind:      kind,
	}
}

package store

import (
	"os"
	"sync"

	"k8s.io/klog/v2"
)

const (
	redisStoreType  = "redis"
	valkeyStoreType = "valkey"
)

var (
	initStoreOnce = &sync.Once{}
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(func() {
		if err := initStore(); err != nil {
			klog.Fatalf("init store failed: %v", err)
		}
	})
	return provider
}

func initStore() error {
	storeType := os.Getenv("STORE_TYPE")
	if storeType == "" {
		storeType = redisStoreType
	}

	var err error
	switch storeType {
	case redisStoreType:
		provider, err = newRedisStore()
		if err != nil {
			return err
		}
	case valkeyStoreType:
		provider, err = newValkeyStore()
		if err != nil {
			return err
		}
	default:
		klog.Fatalf("unsupported store type: %s", storeType)
	}
	return nil
}

package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"time"

	redisv9 "github.com/go-redis/redis/v9"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type redisStore struct {
	cli                 *redisv9.Client
	sessionPrefix       string
	expiryIndexKey      string
	lastActivityIndexKey string
}

func newRedisStore() (Store, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		return nil, errors.New("REDIS_ADDR is required")
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := os.Getenv("REDIS_PASSWORD_REQUIRED")
	if password == "" && passwordRequired != "false" {
		return nil, errors.New("REDIS_PASSWORD is required")
	}

	cli := redisv9.NewClient(&redisv9.Options{
		Addr:     addr,
		Password: password,
	})

	return &redisStore{
		cli:                 cli,
		sessionPrefix:       "session:",
		expiryIndexKey:      "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}, nil
}

func (r *redisStore) Ping(ctx context.Context) error {
	return r.cli.Ping(ctx).Err()
}

func (r *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := r.sessionPrefix + sessionID
	data, err := r.cli.Get(ctx, key).Bytes()
	if err != nil {
		if errors.Is(err, redisv9.Nil) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var info types.SandboxInfo
	if err := json.Unmarshal(data, &info); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox info: %w", err)
	}
	return &info, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox info: %w", err)
	}

	key := r.sessionPrefix + sandboxStore.SessionID

	pipe := r.cli.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, r.expiryIndexKey, redisv9.Z{
		Score:  float64(sandboxStore.ExpiresAt.Unix()),
		Member: sandboxStore.SessionID,
	})
	pipe.ZAdd(ctx, r.lastActivityIndexKey, redisv9.Z{
		Score:  float64(sandboxStore.CreatedAt.Unix()),
		Member: sandboxStore.SessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox info: %w", err)
	}

	key := r.sessionPrefix + sandboxStore.SessionID
	return r.cli.Set(ctx, key, data, 0).Err()
}

func (r *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := r.sessionPrefix + sessionID

	pipe := r.cli.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, r.expiryIndexKey, sessionID)
	pipe.ZRem(ctx, r.lastActivityIndexKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result, err := r.cli.ZRangeByScore(ctx, r.expiryIndexKey, &redisv9.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.batchGetSandboxes(ctx, result)
}

func (r *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result, err := r.cli.ZRangeByScore(ctx, r.lastActivityIndexKey, &redisv9.ZRangeBy{
		Min:   "-inf",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.batchGetSandboxes(ctx, result)
}

func (r *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := r.sessionPrefix + sessionID
	exists, err := r.cli.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	return r.cli.ZAdd(ctx, r.lastActivityIndexKey, redisv9.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	}).Err()
}

func (r *redisStore) Close() error {
	return r.cli.Close()
}

func (r *redisStore) batchGetSandboxes(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	pipe := r.cli.Pipeline()
	cmds := make([]*redisv9.StringCmd, len(sessionIDs))
	for i, id := range sessionIDs {
		key := r.sessionPrefix + id
		cmds[i] = pipe.Get(ctx, key)
	}

	_, err := pipe.Exec(ctx)
	if err != nil && !errors.Is(err, redisv9.Nil) {
		return nil, err
	}

	var sandboxes []*types.SandboxInfo
	for i, cmd := range cmds {
		data, err := cmd.Bytes()
		if err != nil {
			if errors.Is(err, redisv9.Nil) {
				klog.Warningf("session %s not found in store", sessionIDs[i])
				continue
			}
			return nil, err
		}

		var info types.SandboxInfo
		if err := json.Unmarshal(data, &info); err != nil {
			klog.Warningf("failed to unmarshal sandbox info for session %s: %v", sessionIDs[i], err)
			continue
		}
		sandboxes = append(sandboxes, &info)
	}

	return sandboxes, nil
}

package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type valkeyStore struct {
	cli                  valkey.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func newValkeyStore() (Store, error) {
	addrs := os.Getenv("VALKEY_ADDR")
	if addrs == "" {
		return nil, errors.New("VALKEY_ADDR is required")
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := os.Getenv("VALKEY_PASSWORD_REQUIRED")
	if password == "" && passwordRequired != "false" {
		return nil, errors.New("VALKEY_PASSWORD is required")
	}

	opts := valkey.ClientOption{
		InitAddress: strings.Split(addrs, ","),
		Password:    password,
	}

	if os.Getenv("VALKEY_DISABLE_CACHE") == "true" {
		opts.DisableCache = true
	}

	if os.Getenv("VALKEY_FORCE_SINGLE") == "true" {
		opts.ForceSingle = true
	}

	cli, err := valkey.NewClient(opts)
	if err != nil {
		return nil, fmt.Errorf("failed to create valkey client: %w", err)
	}

	return &valkeyStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:       "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}, nil
}

func (v *valkeyStore) Ping(ctx context.Context) error {
	return v.cli.Do(ctx, v.cli.B().Ping().Build()).Error()
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := v.sessionPrefix + sessionID
	result := v.cli.Do(ctx, v.cli.B().Get().Key(key).Build())
	if err := result.Error(); err != nil {
		if isValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	data, err := result.AsBytes()
	if err != nil {
		return nil, err
	}

	var info types.SandboxInfo
	if err := json.Unmarshal(data, &info); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox info: %w", err)
	}
	return &info, nil
}

func (v *valkeyStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox info: %w", err)
	}

	key := v.sessionPrefix + sandboxStore.SessionID

	commands := []valkey.Completed{
		v.cli.B().Setnx().Key(key).Value(string(data)).Build(),
		v.cli.B().Zadd().Key(v.expiryIndexKey).ScoreMember().
			ScoreMember(valkey.Z{Score: float64(sandboxStore.ExpiresAt.Unix()), Member: sandboxStore.SessionID}).Build(),
		v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().
			ScoreMember(valkey.Z{Score: float64(sandboxStore.CreatedAt.Unix()), Member: sandboxStore.SessionID}).Build(),
	}

	for _, cmd := range commands {
		if err := v.cli.Do(ctx, cmd).Error(); err != nil {
			return err
		}
	}
	return nil
}

func (v *valkeyStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox info: %w", err)
	}

	key := v.sessionPrefix + sandboxStore.SessionID
	return v.cli.Do(ctx, v.cli.B().Set().Key(key).Value(string(data)).Build()).Error()
}

func (v *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := v.sessionPrefix + sessionID

	commands := []valkey.Completed{
		v.cli.B().Del().Key(key).Build(),
		v.cli.B().Zrem().Key(v.expiryIndexKey).Member(sessionID).Build(),
		v.cli.B().Zrem().Key(v.lastActivityIndexKey).Member(sessionID).Build(),
	}

	for _, cmd := range commands {
		if err := v.cli.Do(ctx, cmd).Error(); err != nil {
			return err
		}
	}
	return nil
}

func (v *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result := v.cli.Do(ctx, v.cli.B().Zrangebyscore().
		Key(v.expiryIndexKey).
		Min("-inf").
		Max(fmt.Sprintf("%d", before.Unix())).
		Limit(0, limit).
		Build())

	if err := result.Error(); err != nil {
		return nil, err
	}

	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, err
	}

	return v.batchGetSandboxes(ctx, sessionIDs)
}

func (v *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result := v.cli.Do(ctx, v.cli.B().Zrangebyscore().
		Key(v.lastActivityIndexKey).
		Min("-inf").
		Max(fmt.Sprintf("%d", before.Unix())).
		Limit(0, limit).
		Build())

	if err := result.Error(); err != nil {
		return nil, err
	}

	sessionIDs, err := result.AsStrSlice()
	if err != nil {
		return nil, err
	}

	return v.batchGetSandboxes(ctx, sessionIDs)
}

func (v *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := v.sessionPrefix + sessionID
	result := v.cli.Do(ctx, v.cli.B().Exists().Key(key).Build())
	if err := result.Error(); err != nil {
		return err
	}

	count, err := result.AsInt64()
	if err != nil {
		return err
	}
	if count == 0 {
		return ErrNotFound
	}

	return v.cli.Do(ctx, v.cli.B().Zadd().Key(v.lastActivityIndexKey).
		ScoreMember().ScoreMember(valkey.Z{Score: float64(at.Unix()), Member: sessionID}).Build()).Error()
}

func (v *valkeyStore) Close() error {
	v.cli.Close()
	return nil
}

func (v *valkeyStore) batchGetSandboxes(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	var sandboxes []*types.SandboxInfo
	for _, id := range sessionIDs {
		key := v.sessionPrefix + id
		result := v.cli.Do(ctx, v.cli.B().Get().Key(key).Build())
		if err := result.Error(); err != nil {
			if isValkeyNil(err) {
				klog.Warningf("session %s not found in store", id)
				continue
			}
			return nil, err
		}

		data, err := result.AsBytes()
		if err != nil {
			return nil, err
		}

		var info types.SandboxInfo
		if err := json.Unmarshal(data, &info); err != nil {
			klog.Warningf("failed to unmarshal sandbox info for session %s: %v", id, err)
			continue
		}
		sandboxes = append(sandboxes, &info)
	}

	return sandboxes, nil
}

func isValkeyNil(err error) bool {
	return err != nil && err.Error() == "redis: nil"
}

package picod

type Config struct {
	Port      int    `json:"port"`
	Workspace string `json:"workspace"`
}

package picod

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"time"

	"github.com/gin-gonic/gin"
)

type Server struct {
	config      *Config
	engine      *gin.Engine
	httpServer  *http.Server
	authManager *AuthManager
}

func NewServer(config *Config) *Server {
	gin.SetMode(gin.ReleaseMode)

	engine := gin.New()
	engine.Use(gin.Logger())
	engine.Use(gin.Recovery())

	server := &Server{
		config:      config,
		engine:      engine,
		authManager: NewAuthManager(),
	}

	server.setupRoutes()

	return server
}

func (s *Server) setupRoutes() {
	workspace := s.config.Workspace
	if workspace == "" {
		workspace, _ = os.Getwd()
	}

	s.engine.GET("/health", HealthHandler)

	authGroup := s.engine.Group("/")
	authGroup.Use(s.authManager.AuthMiddleware())
	{
		authGroup.POST("/api/execute", ExecuteHandler(workspace))
		authGroup.POST("/api/files", UploadFileHandler(workspace))
		authGroup.GET("/api/files", ListFilesHandler(workspace))
		authGroup.GET("/api/files/*path", DownloadFileHandler(workspace))
	}
}

func (s *Server) Run() error {
	if err := s.authManager.LoadPublicKeyFromEnv(); err != nil {
		return fmt.Errorf("failed to load public key: %w", err)
	}

	addr := fmt.Sprintf(":%d", s.config.Port)
	s.httpServer = &http.Server{
		Addr:              addr,
		Handler:           s.engine,
		ReadHeaderTimeout: 10 * time.Second,
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.httpServer != nil {
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

func (s *Server) GetAuthManager() *AuthManager {
	return s.authManager
}

package picod

import (
	"context"
	"crypto/rsa"
	"errors"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

const (
	PublicKeyEnvVar = "PICOD_AUTH_PUBLIC_KEY"
	MaxBodySize     = 32 << 20
)

type AuthManager struct {
	publicKey *rsa.PublicKey
	mutex     sync.RWMutex
}

func NewAuthManager() *AuthManager {
	return &AuthManager{}
}

func (am *AuthManager) LoadPublicKeyFromEnv() error {
	pubKeyPEM := os.Getenv(PublicKeyEnvVar)
	if pubKeyPEM == "" {
		return errors.New("PICOD_AUTH_PUBLIC_KEY environment variable is not set")
	}

	pubKeyPEM = strings.TrimSpace(pubKeyPEM)

	block, _ := jwt.ParseRSAPublicKeyFromPEM([]byte(pubKeyPEM))
	if block == nil {
		pubKey, err := jwt.ParseRSAPublicKeyFromPEM([]byte(pubKeyPEM))
		if err != nil {
			return err
		}
		am.mutex.Lock()
		am.publicKey = pubKey
		am.mutex.Unlock()
		return nil
	}

	am.mutex.Lock()
	am.publicKey = block
	am.mutex.Unlock()
	return nil
}

func (am *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "Missing authorization header"})
			c.Abort()
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || !strings.EqualFold(parts[0], "Bearer") {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "Invalid authorization header format"})
			c.Abort()
			return
		}

		tokenString := parts[1]

		am.mutex.RLock()
		pubKey := am.publicKey
		am.mutex.RUnlock()

		if pubKey == nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Public key not loaded"})
			c.Abort()
			return
		}

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, errors.New("unexpected signing method")
			}
			return pubKey, nil
		})

		if err != nil || !token.Valid {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "Invalid token"})
			c.Abort()
			return
		}

		claims, ok := token.Claims.(jwt.MapClaims)
		if !ok {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "Invalid token claims"})
			c.Abort()
			return
		}

		c.Set("claims", claims)

		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize)
		c.Next()
	}
}

func GetClaimsFromContext(ctx context.Context) jwt.MapClaims {
	if ginCtx, ok := ctx.(*gin.Context); ok {
		if claims, exists := ginCtx.Get("claims"); exists {
			if mapClaims, ok := claims.(jwt.MapClaims); ok {
				return mapClaims
			}
		}
	}
	return nil
}

func GetSessionIDFromContext(ctx context.Context) string {
	claims := GetClaimsFromContext(ctx)
	if claims != nil {
		if sessionID, ok := claims["session_id"].(string); ok {
			return sessionID
		}
	}
	return ""
}

func (am *AuthManager) GetPublicKey() *rsa.PublicKey {
	am.mutex.RLock()
	defer am.mutex.RUnlock()
	return am.publicKey
}

func (am *AuthManager) SetPublicKey(key *rsa.PublicKey) {
	am.mutex.Lock()
	defer am.mutex.Unlock()
	am.publicKey = key
}

type contextKey string

const (
	ClaimsContextKey contextKey = "claims"
	SessionContextKey contextKey = "session_id"
)

func GetContextWithClaims(ctx context.Context, claims jwt.MapClaims) context.Context {
	return context.WithValue(ctx, ClaimsContextKey, claims)
}

func GetContextWithSessionID(ctx context.Context, sessionID string) context.Context {
	return context.WithValue(ctx, SessionContextKey, sessionID)
}

package picod

import (
	"bytes"
	"context"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
)

const (
	TimeoutExitCode = 124
	maxFileMode     = 0777
)

type ExecuteRequest struct {
	Command    []string          `json:"command" binding:"required"`
	Timeout    string            `json:"timeout"`
	WorkingDir string            `json:"working_dir"`
	Env        map[string]string `json:"env"`
}

type ExecuteResponse struct {
	Stdout    string    `json:"stdout"`
	Stderr    string    `json:"stderr"`
	ExitCode  int       `json:"exit_code"`
	Duration  float64   `json:"duration"`
	StartTime time.Time `json:"start_time"`
	EndTime   time.Time `json:"end_time"`
}

type FileInfo struct {
	Path     string    `json:"path"`
	Size     int64     `json:"size"`
	Mode     string    `json:"mode"`
	Modified time.Time `json:"modified"`
}

type UploadFileRequest struct {
	Path    string `json:"path" binding:"required"`
	Content string `json:"content" binding:"required"`
	Mode    string `json:"mode"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

type FileEntry struct {
	Name string `json:"name"`
	Type string `json:"type"`
}

func ExecuteHandler(workspace string) gin.HandlerFunc {
	return func(c *gin.Context) {
		var req ExecuteRequest
		if err := c.ShouldBindJSON(&req); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
			return
		}

		if len(req.Command) == 0 {
			c.JSON(http.StatusBadRequest, gin.H{"error": "command is required"})
			return
		}

		timeout := 60 * time.Second
		if req.Timeout != "" {
			if parsed, err := time.ParseDuration(req.Timeout); err == nil {
				timeout = parsed
			}
		}

		ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
		defer cancel()

		workingDir := req.WorkingDir
		if workingDir == "" {
			workingDir = workspace
		}
		workingDir = sanitizePath(workspace, workingDir)

		cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)
		cmd.Dir = workingDir

		if req.Env != nil {
			cmd.Env = os.Environ()
			for k, v := range req.Env {
				cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, v))
			}
		}

		var stdout, stderr bytes.Buffer
		cmd.Stdout = &stdout
		cmd.Stderr = &stderr

		startTime := time.Now()
		err := cmd.Run()
		endTime := time.Now()

		exitCode := 0
		if err != nil {
			if exitErr, ok := err.(*exec.ExitError); ok {
				exitCode = exitErr.ExitCode()
			} else if ctx.Err() == context.DeadlineExceeded {
				exitCode = TimeoutExitCode
			} else {
				exitCode = 1
			}
		}

		response := ExecuteResponse{
			Stdout:    stdout.String(),
			Stderr:    stderr.String(),
			ExitCode:  exitCode,
			Duration:  endTime.Sub(startTime).Seconds(),
			StartTime: startTime,
			EndTime:   endTime,
		}

		c.JSON(http.StatusOK, response)
	}
}

func UploadFileHandler(workspace string) gin.HandlerFunc {
	return func(c *gin.Context) {
		contentType := c.GetHeader("Content-Type")

		if strings.HasPrefix(contentType, "multipart/form-data") {
			file, header, err := c.Request.FormFile("file")
			if err != nil {
				c.JSON(http.StatusBadRequest, gin.H{"error": "failed to get file from form"})
				return
			}
			defer file.Close()

			remotePath := c.PostForm("path")
			if remotePath == "" {
				remotePath = header.Filename
			}

			remotePath = sanitizePath(workspace, remotePath)

			if err := os.MkdirAll(filepath.Dir(remotePath), 0755); err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create directory: %v", err)})
				return
			}

			dst, err := os.Create(remotePath)
			if err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create file: %v", err)})
				return
			}
			defer dst.Close()

			if _, err := io.Copy(dst, file); err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to write file: %v", err)})
				return
			}

			c.JSON(http.StatusOK, gin.H{"path": remotePath, "status": "uploaded"})
			return
		}

		var req UploadFileRequest
		if err := c.ShouldBindJSON(&req); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
			return
		}

		remotePath := sanitizePath(workspace, req.Path)

		content, err := base64.StdEncoding.DecodeString(req.Content)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "failed to decode base64 content"})
			return
		}

		if err := os.MkdirAll(filepath.Dir(remotePath), 0755); err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create directory: %v", err)})
			return
		}

		mode := os.FileMode(0644)
		if req.Mode != "" {
			if m, err := strconv.ParseInt(req.Mode, 8, 32); err == nil {
				mode = os.FileMode(m & maxFileMode)
			}
		}

		if err := os.WriteFile(remotePath, content, mode); err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to write file: %v", err)})
			return
		}

		c.JSON(http.StatusOK, gin.H{"path": remotePath, "status": "created"})
	}
}

func DownloadFileHandler(workspace string) gin.HandlerFunc {
	return func(c *gin.Context) {
		path := c.Param("path")
		path = strings.TrimPrefix(path, "/")
		path = sanitizePath(workspace, path)

		info, err := os.Stat(path)
		if err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": "file not found"})
			return
		}

		if info.IsDir() {
			c.JSON(http.StatusBadRequest, gin.H{"error": "cannot download a directory"})
			return
		}

		c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=%s", filepath.Base(path)))
		c.Header("Content-Type", "application/octet-stream")
		c.File(path)
	}
}

func ListFilesHandler(workspace string) gin.HandlerFunc {
	return func(c *gin.Context) {
		path := c.Query("path")
		if path == "" {
			c.JSON(http.StatusBadRequest, gin.H{"error": "path query parameter is required"})
			return
		}

		path = sanitizePath(workspace, path)

		entries, err := os.ReadDir(path)
		if err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("failed to read directory: %v", err)})
			return
		}

		var files []FileEntry
		for _, entry := range entries {
			fileType := "file"
			if entry.IsDir() {
				fileType = "directory"
			}
			files = append(files, FileEntry{
				Name: entry.Name(),
				Type: fileType,
			})
		}

		c.JSON(http.StatusOK, ListFilesResponse{Files: files})
	}
}

func sanitizePath(workspace, path string) string {
	if filepath.IsAbs(path) {
		return path
	}

	absPath := filepath.Join(workspace, path)
	absPath = filepath.Clean(absPath)

	if !strings.HasPrefix(absPath, workspace) {
		return workspace
	}

	return absPath
}

func HealthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

package main

import (
	"flag"
	"os"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/picod"
)

func main() {
	port := flag.Int("port", 8080, "The port to listen on")
	workspace := flag.String("workspace", "", "The workspace directory (defaults to current working directory)")

	klog.InitFlags(nil)
	flag.Parse()

	if *workspace == "" {
		wd, err := os.Getwd()
		if err != nil {
			klog.Fatalf("Failed to get working directory: %v", err)
		}
		*workspace = wd
	}

	config := &picod.Config{
		Port:      *port,
		Workspace: *workspace,
	}

	server := picod.NewServer(config)

	klog.Infof("Starting PicoD server on port %d, workspace: %s", *port, *workspace)

	if err := server.Run(); err != nil {
		klog.Fatalf("Server failed: %v", err)
	}
}

