package picod

import (
	"bytes"
	"context"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
)

const (
	TimeoutExitCode = 124
	maxFileMode     = 0777
)

type ExecuteRequest struct {
	Command    []string          `json:"command" binding:"required"`
	Timeout    string            `json:"timeout"`
	WorkingDir string            `json:"working_dir"`
	Env        map[string]string `json:"env"`
}

type ExecuteResponse struct {
	Stdout    string    `json:"stdout"`
	Stderr    string    `json:"stderr"`
	ExitCode  int       `json:"exit_code"`
	Duration  float64   `json:"duration"`
	StartTime time.Time `json:"start_time"`
	EndTime   time.Time `json:"end_time"`
}

type FileInfo struct {
	Path     string    `json:"path"`
	Size     int64     `json:"size"`
	Mode     string    `json:"mode"`
	Modified time.Time `json:"modified"`
}

type UploadFileRequest struct {
	Path    string `json:"path" binding:"required"`
	Content string `json:"content" binding:"required"`
	Mode    string `json:"mode"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

type FileEntry struct {
	Name string `json:"name"`
	Type string `json:"type"`
}

func ExecuteHandler(workspace string) gin.HandlerFunc {
	return func(c *gin.Context) {
		var req ExecuteRequest
		if err := c.ShouldBindJSON(&req); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
			return
		}

		if len(req.Command) == 0 {
			c.JSON(http.StatusBadRequest, gin.H{"error": "command is required"})
			return
		}

		timeout := 60 * time.Second
		if req.Timeout != "" {
			if parsed, err := time.ParseDuration(req.Timeout); err == nil {
				timeout = parsed
			}
		}

		ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
		defer cancel()

		workingDir := req.WorkingDir
		if workingDir == "" {
			workingDir = workspace
		}
		workingDir = sanitizePath(workspace, workingDir)

		cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)
		cmd.Dir = workingDir

		if req.Env != nil {
			cmd.Env = os.Environ()
			for k, v := range req.Env {
				cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, v))
			}
		}

		var stdout, stderr bytes.Buffer
		cmd.Stdout = &stdout
		cmd.Stderr = &stderr

		startTime := time.Now()
		err := cmd.Run()
		endTime := time.Now()

		exitCode := 0
		if err != nil {
			if exitErr, ok := err.(*exec.ExitError); ok {
				exitCode = exitErr.ExitCode()
			} else if ctx.Err() == context.DeadlineExceeded {
				exitCode = TimeoutExitCode
			} else {
				exitCode = 1
			}
		}

		response := ExecuteResponse{
			Stdout:    stdout.String(),
			Stderr:    stderr.String(),
			ExitCode:  exitCode,
			Duration:  endTime.Sub(startTime).Seconds(),
			StartTime: startTime,
			EndTime:   endTime,
		}

		c.JSON(http.StatusOK, response)
	}
}

func UploadFileHandler(workspace string) gin.HandlerFunc {
	return func(c *gin.Context) {
		contentType := c.GetHeader("Content-Type")

		if strings.HasPrefix(contentType, "multipart/form-data") {
			file, header, err := c.Request.FormFile("file")
			if err != nil {
				c.JSON(http.StatusBadRequest, gin.H{"error": "failed to get file from form"})
				return
			}
			defer file.Close()

			remotePath := c.PostForm("path")
			if remotePath == "" {
				remotePath = header.Filename
			}

			remotePath = sanitizePath(workspace, remotePath)

			if err := os.MkdirAll(filepath.Dir(remotePath), 0755); err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create directory: %v", err)})
				return
			}

			dst, err := os.Create(remotePath)
			if err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create file: %v", err)})
				return
			}
			defer dst.Close()

			if _, err := io.Copy(dst, file); err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to write file: %v", err)})
				return
			}

			c.JSON(http.StatusOK, gin.H{"path": remotePath, "status": "uploaded"})
			return
		}

		var req UploadFileRequest
		if err := c.ShouldBindJSON(&req); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
			return
		}

		remotePath := sanitizePath(workspace, req.Path)

		content, err := base64.StdEncoding.DecodeString(req.Content)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "failed to decode base64 content"})
			return
		}

		if err := os.MkdirAll(filepath.Dir(remotePath), 0755); err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create directory: %v", err)})
			return
		}

		mode := os.FileMode(0644)
		if req.Mode != "" {
			if m, err := strconv.ParseInt(req.Mode, 8, 32); err == nil {
				mode = os.FileMode(m & maxFileMode)
			}
		}

		if err := os.WriteFile(remotePath, content, mode); err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to write file: %v", err)})
			return
		}

		c.JSON(http.StatusOK, gin.H{"path": remotePath, "status": "created"})
	}
}

func DownloadFileHandler(workspace string) gin.HandlerFunc {
	return func(c *gin.Context) {
		path := c.Param("path")
		path = strings.TrimPrefix(path, "/")
		path = sanitizePath(workspace, path)

		info, err := os.Stat(path)
		if err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": "file not found"})
			return
		}

		if info.IsDir() {
			c.JSON(http.StatusBadRequest, gin.H{"error": "cannot download a directory"})
			return
		}

		c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=%s", filepath.Base(path)))
		c.Header("Content-Type", "application/octet-stream")
		c.File(path)
	}
}

func ListFilesHandler(workspace string) gin.HandlerFunc {
	return func(c *gin.Context) {
		path := c.Query("path")
		if path == "" {
			c.JSON(http.StatusBadRequest, gin.H{"error": "path query parameter is required"})
			return
		}

		path = sanitizePath(workspace, path)

		entries, err := os.ReadDir(path)
		if err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("failed to read directory: %v", err)})
			return
		}

		var files []FileEntry
		for _, entry := range entries {
			fileType := "file"
			if entry.IsDir() {
				fileType = "directory"
			}
			files = append(files, FileEntry{
				Name: entry.Name(),
				Type: fileType,
			})
		}

		c.JSON(http.StatusOK, ListFilesResponse{Files: files})
	}
}

func sanitizePath(workspace, path string) string {
	if filepath.IsAbs(path) {
		return path
	}

	absPath := filepath.Join(workspace, path)
	absPath = filepath.Clean(absPath)

	if !strings.HasPrefix(absPath, workspace) {
		return workspace
	}

	return absPath
}

func HealthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

