package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"time"

	"github.com/golang-jwt/jwt/v5"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
)

const (
	rsaKeySize      = 2048
	jwtExpiration   = 5 * time.Minute
	IdentitySecretName = "picod-router-identity"
)

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
	namespace  string
}

func NewJWTManager(clientset kubernetes.Interface) (*JWTManager, error) {
	privateKey, err := rsa.GenerateKey(rand.Reader, rsaKeySize)
	if err != nil {
		return nil, fmt.Errorf("failed to generate RSA key pair: %w", err)
	}

	namespace := os.Getenv("AGENTCUBE_NAMESPACE")
	if namespace == "" {
		namespace = "default"
	}

	return &JWTManager{
		privateKey: privateKey,
		publicKey:  &privateKey.PublicKey,
		clientset:  clientset,
		namespace:  namespace,
	}, nil
}

type TokenClaims struct {
	SessionID string `json:"session_id"`
	jwt.RegisteredClaims
}

func (j *JWTManager) GenerateToken(sessionID string) (string, error) {
	now := time.Now()
	claims := TokenClaims{
		SessionID: sessionID,
		RegisteredClaims: jwt.RegisteredClaims{
			ExpiresAt: jwt.NewNumericDate(now.Add(jwtExpiration)),
			IssuedAt:  jwt.NewNumericDate(now),
			Issuer:    "agentcube-router",
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) GetPublicKeyPEM() (string, error) {
	pubKeyBytes, err := x509.MarshalPKIXPublicKey(j.publicKey)
	if err != nil {
		return "", fmt.Errorf("failed to marshal public key: %w", err)
	}

	pubKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: pubKeyBytes,
	})

	return string(pubKeyPEM), nil
}

func (j *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	secret, err := j.clientset.CoreV1().Secrets(j.namespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		if !errors.IsNotFound(err) {
			return fmt.Errorf("failed to get identity secret: %w", err)
		}

		return j.createIdentitySecret(ctx)
	}

	privateKeyPEM := secret.Data["private-key"]
	if len(privateKeyPEM) > 0 {
		block, _ := pem.Decode(privateKeyPEM)
		if block != nil {
			privateKey, err := x509.ParsePKCS1PrivateKey(block.Bytes)
			if err == nil {
				j.privateKey = privateKey
				j.publicKey = &privateKey.PublicKey
				klog.Info("Loaded existing RSA key pair from secret")
				return nil
			}
		}
	}

	return j.updateIdentitySecret(ctx, secret)
}

func (j *JWTManager) createIdentitySecret(ctx context.Context) error {
	privateKeyBytes := x509.MarshalPKCS1PrivateKey(j.privateKey)
	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: privateKeyBytes,
	})

	pubKeyBytes, err := x509.MarshalPKIXPublicKey(j.publicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %w", err)
	}
	pubKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: pubKeyBytes,
	})

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: j.namespace,
		},
		Data: map[string][]byte{
			"private-key": privateKeyPEM,
			"public-key":  pubKeyPEM,
		},
	}

	_, err = j.clientset.CoreV1().Secrets(j.namespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		return fmt.Errorf("failed to create identity secret: %w", err)
	}

	klog.Info("Created new RSA key pair and stored in secret")
	return nil
}

func (j *JWTManager) updateIdentitySecret(ctx context.Context, existing *corev1.Secret) error {
	privateKeyBytes := x509.MarshalPKCS1PrivateKey(j.privateKey)
	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: privateKeyBytes,
	})

	pubKeyBytes, err := x509.MarshalPKIXPublicKey(j.publicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %w", err)
	}
	pubKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: pubKeyBytes,
	})

	existing.Data = map[string][]byte{
		"private-key": privateKeyPEM,
		"public-key":  pubKeyPEM,
	}

	_, err = j.clientset.CoreV1().Secrets(j.namespace).Update(ctx, existing, metav1.UpdateOptions{})
	if err != nil {
		return fmt.Errorf("failed to update identity secret: %w", err)
	}

	klog.Info("Updated RSA key pair in secret")
	return nil
}

