package router

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"os"
	"strings"
	"time"

	"golang.org/x/net/http2"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

const SessionHeaderKey = "x-agentcube-session-id"

var (
	ErrSessionNotFound      = errors.New("session not found")
	ErrSandboxTemplateNotFound = errors.New("sandbox template not found")
)

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error)
}

type manager struct {
	storeClient      store.Store
	workloadMgrAddr  string
	httpClient       *http.Client
}

func NewSessionManager(storeClient store.Store) (SessionManager, error) {
	workloadMgrAddr := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadMgrAddr == "" {
		return nil, errors.New("WORKLOAD_MANAGER_URL environment variable is required")
	}

	transport := &http.Transport{
		MaxIdleConnsPerHost: 100,
		IdleConnTimeout:     90 * time.Second,
	}

	http2.ConfigureTransport(transport)

	httpClient := &http.Client{
		Timeout:   2 * time.Minute,
		Transport: transport,
	}

	return &manager{
		storeClient:     storeClient,
		workloadMgrAddr: workloadMgrAddr,
		httpClient:      httpClient,
	}, nil
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID, namespace, name, kind string) (*types.SandboxInfo, error) {
	if sessionID == "" {
		return m.createSandbox(ctx, namespace, name, kind)
	}

	sandbox, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			return nil, api.NewSessionNotFoundError(sessionID)
		}
		return nil, fmt.Errorf("failed to get sandbox from store: %w", err)
	}

	return sandbox, nil
}

func (m *manager) createSandbox(ctx context.Context, namespace, name, kind string) (*types.SandboxInfo, error) {
	reqBody := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	bodyBytes, err := json.Marshal(reqBody)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	var endpoint string
	switch strings.ToLower(kind) {
	case "agentruntime", "agent-runtime":
		endpoint = fmt.Sprintf("%s/v1/agent-runtime", m.workloadMgrAddr)
	case "codeinterpreter", "code-interpreter":
		endpoint = fmt.Sprintf("%s/v1/code-interpreter", m.workloadMgrAddr)
	default:
		return nil, fmt.Errorf("unsupported kind: %s", kind)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, endpoint, strings.NewReader(string(bodyBytes)))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := m.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("failed to send request to workload manager: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode == http.StatusNotFound {
		return nil, api.NewSandboxTemplateNotFoundError(namespace, name, kind)
	}

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(resp.Body)
		return nil, fmt.Errorf("workload manager returned status %d: %s", resp.StatusCode, string(body))
	}

	var response types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&response); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	sandbox, err := m.storeClient.GetSandboxBySessionID(ctx, response.SessionID)
	if err != nil {
		return nil, fmt.Errorf("failed to get created sandbox: %w", err)
	}

	return sandbox, nil
}

func GetBaseURL(routerURL, namespace, crName, crKind string) string {
	var resourceType string
	switch strings.ToLower(crKind) {
	case "agentruntime", "agent-runtime":
		resourceType = "agent-runtimes"
	case "codeinterpreter", "code-interpreter":
		resourceType = "code-interpreters"
	default:
		resourceType = "agent-runtimes"
	}

	baseURL, err := url.JoinPath(routerURL, "/v1/namespaces", namespace, resourceType, crName, "invocations/")
	if err != nil {
		klog.Warningf("Failed to join URL path: %v", err)
		return fmt.Sprintf("%s/v1/namespaces/%s/%s/%s/invocations/", routerURL, namespace, resourceType, crName)
	}

	return baseURL
}

package router

import (
	"context"
	"errors"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type ResourceKind string

const (
	KindAgentRuntime    ResourceKind = "agent-runtime"
	KindCodeInterpreter ResourceKind = "code-interpreter"
)

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{"status": "not ready", "error": "session manager not initialized"})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) handleAgentInvoke(c *gin.Context) {
	s.handleInvoke(c, KindAgentRuntime)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	s.handleInvoke(c, KindCodeInterpreter)
}

func (s *Server) handleInvoke(c *gin.Context, kind ResourceKind) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sessionID := c.GetHeader(SessionHeaderKey)

	ctx := c.Request.Context()

	sandbox, err := s.sessionManager.GetSandboxBySession(ctx, sessionID, namespace, name, string(kind))
	if err != nil {
		handleSessionError(c, err)
		return
	}

	if err := s.updateLastActivity(ctx, sandbox); err != nil {
		klog.Warningf("Failed to update last activity for session %s: %v", sandbox.SessionID, err)
	}

	if err := s.forwardToSandbox(c, sandbox, path); err != nil {
		handleForwardError(c, err)
		return
	}

	c.Header(SessionHeaderKey, sandbox.SessionID)
}

func (s *Server) updateLastActivity(ctx context.Context, sandbox *types.SandboxInfo) error {
	return s.storeClient.UpdateSessionLastActivity(ctx, sandbox.SessionID, time.Now())
}

func (s *Server) forwardToSandbox(c *gin.Context, sandbox *types.SandboxInfo, path string) error {
	if len(sandbox.EntryPoints) == 0 {
		return errors.New("no entry points available for sandbox")
	}

	var targetEntry *types.SandboxEntryPoint
	for i := range sandbox.EntryPoints {
		if path != "" && strings.HasPrefix(path, sandbox.EntryPoints[i].Path) {
			targetEntry = &sandbox.EntryPoints[i]
			break
		}
	}
	if targetEntry == nil {
		targetEntry = &sandbox.EntryPoints[0]
	}

	targetURL, err := url.Parse(targetEntry.Endpoint)
	if err != nil {
		return fmt.Errorf("failed to parse entry point endpoint: %w", err)
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = targetURL.Scheme
		req.URL.Host = targetURL.Host
		req.URL.Path = singleJoiningSlash(targetURL.Path, path)
		req.Host = targetURL.Host

		if _, ok := req.Header["User-Agent"]; !ok {
			req.Header.Set("User-Agent", "agentcube-router")
		}

		for key, values := range c.Request.Header {
			for _, value := range values {
				req.Header.Add(key, value)
			}
		}

		if s.jwtManager != nil {
			token, err := s.jwtManager.GenerateToken(sandbox.SessionID)
			if err != nil {
				klog.Warningf("Failed to generate JWT token: %v", err)
			} else {
				req.Header.Set("Authorization", "Bearer "+token)
			}
		}
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		klog.Errorf("Proxy error for %s: %v", r.URL.Path, err)
	}

	proxy.ServeHTTP(c.Writer, c.Request)
	return nil
}

func handleSessionError(c *gin.Context, err error) {
	klog.Errorf("Session error: %v", err)
	c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
}

func handleForwardError(c *gin.Context, err error) {
	klog.Errorf("Forward error: %v", err)

	var netErr net.Error
	if errors.As(err, &netErr) {
		if netErr.Timeout() {
			c.JSON(http.StatusGatewayTimeout, gin.H{"error": "upstream timeout"})
			return
		}
		if netErr.(*net.OpError) != nil {
			c.JSON(http.StatusBadGateway, gin.H{"error": "connection refused"})
			return
		}
	}

	c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
}

func singleJoiningSlash(a, b string) string {
	aslash := strings.HasSuffix(a, "/")
	bslash := strings.HasPrefix(b, "/")
	switch {
	case aslash && bslash:
		return a + b[1:]
	case !aslash && !bslash:
		return a + "/" + b
	}
	return a + b
}

func copyHeader(dst, src http.Header) {
	for k, vv := range src {
		for _, v := range vv {
			dst.Add(k, v)
		}
	}
}

type responseWriter struct {
	http.ResponseWriter
	statusCode int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

type responseCapture struct {
	body io.Writer
	http.ResponseWriter
}

func (rc *responseCapture) Write(b []byte) (int, error) {
	return rc.body.Write(b)
}

package router

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type Server struct {
	config          *Config
	engine          *gin.Engine
	httpServer      *http.Server
	sessionManager  SessionManager
	storeClient     store.Store
	httpTransport   *http.Transport
	jwtManager      *JWTManager
	semaphore       chan struct{}
}

func NewServer(config *Config, storeClient store.Store, clientset kubernetes.Interface) (*Server, error) {
	gin.SetMode(gin.ReleaseMode)
	if config.Debug {
		gin.SetMode(gin.DebugMode)
	}

	engine := gin.New()
	engine.Use(gin.Logger())
	engine.Use(gin.Recovery())

	sessionManager, err := NewSessionManager(storeClient)
	if err != nil {
		return nil, fmt.Errorf("failed to create session manager: %w", err)
	}

	var jwtManager *JWTManager
	if clientset != nil {
		jwtManager, err = NewJWTManager(clientset)
		if err != nil {
			klog.Warningf("Failed to create JWT manager: %w", err)
		}
	}

	maxConcurrent := config.MaxConcurrentRequests
	if maxConcurrent <= 0 {
		maxConcurrent = 1000
	}

	s := &Server{
		config:         config,
		engine:         engine,
		sessionManager: sessionManager,
		storeClient:    storeClient,
		jwtManager:     jwtManager,
		semaphore:      make(chan struct{}, maxConcurrent),
	}

	s.setupRoutes()

	return s, nil
}

func (s *Server) setupRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	invocationGroup := s.engine.Group("/")
	invocationGroup.Use(s.concurrencyMiddleware())
	{
		invocationGroup.GET("/v1/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		invocationGroup.POST("/v1/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		invocationGroup.GET("/v1/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
		invocationGroup.POST("/v1/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
	}
}

func (s *Server) concurrencyMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		select {
		case s.semaphore <- struct{}{}:
			defer func() { <-s.semaphore }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{"error": "too many requests"})
			c.Abort()
		}
	}
}

func (s *Server) Run() error {
	if s.jwtManager != nil {
		ctx := context.Background()
		if err := s.jwtManager.TryStoreOrLoadJWTKeySecret(ctx); err != nil {
			klog.Warningf("Failed to store or load JWT key secret: %v", err)
		}
	}

	addr := fmt.Sprintf(":%s", s.config.Port)

	var handler http.Handler = s.engine
	if !s.config.EnableTLS {
		h2s := &http2.Server{}
		handler = h2c.NewHandler(s.engine, h2s)
	}

	s.httpServer = &http.Server{
		Addr:         addr,
		Handler:      handler,
		ReadTimeout:  30 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	if s.config.EnableTLS {
		klog.Infof("Starting HTTPS server on %s", addr)
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	klog.Infof("Starting HTTP server on %s", addr)
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.httpServer != nil {
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

func (s *Server) GetSessionManager() SessionManager {
	return s.sessionManager
}

func (s *Server) GetJWTManager() *JWTManager {
	return s.jwtManager
}

func GetNamespace() string {
	ns := os.Getenv("AGENTCUBE_NAMESPACE")
	if ns == "" {
		return "default"
	}
	return ns
}

func getRouterURL() string {
	return strings.TrimSuffix(os.Getenv("ROUTER_URL"), "/")
}

var (
	clientsetCache     kubernetes.Interface
	clientsetCacheOnce sync.Once
)

func GetClientset() kubernetes.Interface {
	clientsetCacheOnce.Do(func() {
		cfg, err := kubernetes.NewInClusterConfig()
		if err != nil {
			klog.Warningf("Failed to get in-cluster config: %v", err)
			return
		}
		clientsetCache, err = kubernetes.NewForConfig(cfg)
		if err != nil {
			klog.Warningf("Failed to create clientset: %v", err)
		}
	})
	return clientsetCache
}

